// Zero-result search beacon. Fire-and-forget log through the EXISTING
// first-party analytics proxy at /api/analytics (same envelope as
// components/web-vitals-reporter.tsx — no new vendor, no hand-rolled HMAC).
// The query string is the only payload and is truncated to 80 chars.
// Fail-open everywhere: a beacon must never throw or block the dialog.

import { truncateQuery } from "@/lib/search-relevance";

const PROJECT_ID = "orchestkit";
const ENDPOINT = "/api/analytics";

/** Report a query that returned zero results. Safe to call anywhere client-side. */
export function reportZeroResultQuery(query: string): void {
	try {
		if (process.env.NODE_ENV === "development") return;
		const truncated = truncateQuery(query);
		if (!truncated) return;
		const body = JSON.stringify({
			project_id: PROJECT_ID,
			events: [
				{
					name: "search:zero-results",
					path: window.location.pathname,
					referrer: "",
					properties: { query: truncated },
				},
			],
		});
		if (
			typeof navigator !== "undefined" &&
			typeof navigator.sendBeacon === "function"
		) {
			navigator.sendBeacon(
				ENDPOINT,
				new Blob([body], { type: "application/json" }),
			);
		} else {
			void fetch(ENDPOINT, {
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body,
				keepalive: true,
			}).catch(() => {});
		}
	} catch {
		// fail-open
	}
}
